resource "aws_iam_role" "synthetic_role_147" {
  name = "synthetic_role_147"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "synthetic_role_147_policy" {
  name   = "synthetic_role_147-policy"
  role   = aws_iam_role.synthetic_role_147.id
  policy = jsonencode({
    "Version": "2012-10-17",
    "Statement": [
        {
            "Effect": "Allow",
            "Action": [
                "*",
                "*"
            ],
            "Resource": "arn:aws:lambda:*:*:*",
            "Condition": {
                "StringEquals": {
                    "aws:PrincipalType": "Service"
                }
            }
        }
    ]
})
}
